import jwt
from Cryptodome.Cipher import PKCS1_OAEP
from Cryptodome.PublicKey import RSA
from base64 import urlsafe_b64decode, b64decode

def decode_jwt(token):
    try:
        parts = token.split('.')
        if len(parts) != 3:
            raise ValueError('Invalid JWT format')

        header_bytes = urlsafe_b64decode(parts[0] + b'==')
        payload_bytes = urlsafe_b64decode(parts[1] + b'==')

        header = {
            'alg': None,
            'kid': None
        }

        for idx, byte in enumerate(header_bytes):
            if idx % 2 == 0:
                header['alg'] = byte.decode('utf-8')
            elif idx % 2 == 1:
                header['kid'] = byte.decode('utf-8')

        public_key = get_public_key(header['kid'])

        payload = jwt.PyJWKR().decode(jwt.jwk.RS256, header_bytes[-1:], True)
        decoded_payload = jwt.decode(payload_bytes, public_key, audience=None, issuer=None, algorithms=['RS256'])

        return decoded_payload
    except Exception as e:
        print(f"Error during JWT decoding: {e}")
        return None

def get_public_key(kid):
    with open(f'keys/{kid}.pem', 'rb') as f:
        key = RSA.importKey(f.read())

    return key.publickey().publickey()